/**
 * XFlow 流程图编辑器模块。
 *
 * 基于 AntV X6 v3 实现，通过 Vite 多入口独立打包为 `flow.xui.js`。
 * X6 库通过 `<script>` 标签全局引入，不参与 Vite 打包（见 `declare var X6`）。
 *
 * 主要导出：
 * - {@link flow.patterns}  — 流程节点类型模板，供侧边栏拖拽使用
 * - {@link flow.FlowEditor} — 流程图编辑器类，支持编辑模式与监控模式
 *
 * ## 编辑模式（editModel: true）
 * - 从侧边栏（Stencil）拖拽节点到画布
 * - 节点间拖拽连线
 * - 键盘快捷键：复制/粘贴/撤销/重做/全选/删除/缩放
 * - 双击节点或边打开属性编辑弹窗（EasyUI window）
 * - 导出流程定义 JSON
 *
 * ## 监控模式（editModel: false / 不传）
 * - 仅展示流程图，不可编辑
 * - 通过不同 node shape 反映节点运行状态（w-node / h-node / l-node / c-node）
 */

// X6 通过 <script> 全局引入，此处仅做类型消音
declare var X6: any;

export namespace flow {

    /**
     * 流程节点类型模板。
     *
     * 定义侧边栏（Stencil）中可拖拽的节点类型，每项包含：
     * - `xtype`：节点业务类型标识，保存到 cell prop，后端据此区分节点行为
     * - `label`：侧边栏显示名称
     * - `image`：节点图标路径
     */
    export const patterns = [
        { xtype: 'userTask',          label: '用户',   image: 'images/flow/usertask.png' },
        { xtype: 'manualTask',        label: '手工',   image: 'images/flow/manualtask.png' },
        { xtype: 'scriptTask',        label: '脚本',   image: 'images/flow/scriptask.png' },
        { xtype: 'serviceTask',       label: '服务',   image: 'images/flow/servicetask.png' },
        { xtype: 'parallelGateway',   label: '并行',   image: 'images/flow/parallel.png' },
        { xtype: 'exclusiveGateway',  label: '排他',   image: 'images/flow/exclusive.png' },
        { xtype: 'inclusiveGateway',  label: '包含',   image: 'images/flow/inclusive.png' },
        { xtype: 'complexGateway',    label: '复杂',   image: 'images/flow/complex.png' },
        { xtype: 'andGateway',        label: 'AND',    image: 'images/flow/and.png' },
        { xtype: 'orGateway',         label: 'OR',     image: 'images/flow/or.png' },
        { xtype: 'threshold',         label: '阈值',   image: 'images/flow/threshold.gif' },
        { xtype: 'timeRobot',         label: '时间',   image: 'images/flow/timerobt.png' },
        { xtype: 'approbt',           label: '应用',   image: 'images/flow/approbt.gif' },
        { xtype: 'thingTask',         label: 'Thing',  image: 'images/flow/thingtask.png' },
        { xtype: 'groundEvent',       label: '接地',   image: 'images/flow/ground.png' },
        { xtype: 'endEvent',          label: '结束',   image: 'images/flow/end.png' },
    ];

    /**
     * 流程图编辑器。
     *
     * 封装 AntV X6 Graph 的创建、节点/边注册、交互配置及流程数据的导入导出。
     * 支持两种模式：
     * - **编辑模式**（`properties.editModel = true`）：启用 Stencil 拖拽、连线、快捷键
     * - **监控模式**（默认）：只读展示，用不同 node shape 反映实例运行状态
     *
     * @example
     * // 编辑模式
     * const editor = new flow.FlowEditor(
     *   document.getElementById('stencil'),
     *   document.getElementById('container'),
     *   { editModel: true }
     * );
     * editor.loadFlowEditor(flowJson); // 从服务端加载流程 JSON
     *
     * @example
     * // 监控模式
     * const viewer = new flow.FlowEditor(null, document.getElementById('container'));
     * viewer.loadFlowEditor(monitorJson);
     */
    export class FlowEditor {
        /** 侧边栏容器 DOM（编辑模式）；监控模式为 null */
        private readonly domStencil: HTMLElement | null;
        /** 画布容器 DOM */
        private readonly domGraph: HTMLElement;
        /** X6 Graph 实例 */
        private graph: any;
        /** 当前选中的 node id → node 映射 */
        private selected: Map<string, any>;
        /** 配置项：{ editModel?: boolean, ... } */
        private properties: Record<string, any>;
        /** 当前加载的流程元数据：{ number, name, instructions, variables } */
        private xflow: any;
        /** X6 Stencil 实例（编辑模式） */
        private stencil: any;
        /** EasyUI window 的 jQuery 对象，用作属性编辑弹窗 */
        private flowWindow: any;

        /**
         * @param dom_stencil - 侧边栏容器元素，监控模式传 null
         * @param dom_g       - 画布容器元素
         * @param properties  - 可选配置；`editModel: true` 启用编辑模式
         */
        constructor(dom_stencil: HTMLElement | null, dom_g: HTMLElement, properties?: Record<string, any>) {
            this.domStencil = dom_stencil;
            this.domGraph = dom_g;
            this.selected = new Map();
            this.properties = properties || {};

            // 1) 注册自定义节点/边类型（x-node / x-edge / w-node 等）
            this.defineFlowNodeType();

            // 2) 创建 X6 Graph 画布
            this.createFlowEditor();

            // 3) 编辑模式：初始化侧边栏 + 键盘快捷键
            if (this.domStencil && this.properties.editModel) {
                this.bindFlowEditorKey();
                this.stencil = this.createFlowStencil();
                this.domStencil.appendChild(this.stencil.container);
                this.loadFlowStencil(patterns, 'workflow');
            }

            // 4) 确保 EasyUI 弹窗容器存在，用于节点/边属性编辑
            this.flowWindow = jQuery('#xx_flow_win_yy');
            if (this.flowWindow.length == 0) {
                jQuery(document.body).append(
                    '<div id="xx_flow_win_yy" style="display:none;width:1024px;height:450px"></div>'
                );
                this.flowWindow = jQuery('#xx_flow_win_yy');
            }
        }

        /**
         * 从服务端 JSON 加载流程图到画布。
         *
         * JSON 格式为 X6 `fromJSON` 兼容结构，包含 `nodes`、`edges` 数组，
         * 每个元素含 `shape`、`attrs`、`id` 等 X6 原生字段及自定义 props。
         *
         * @param json - 流程定义 JSON（含 number/name/instructions/variables/nodes/edges）
         */
        public loadFlowEditor(json: any): void {
            this.xflow = {
                number: json.number,
                name: json.name,
                instructions: json.instructions,
                variables: json.variables,
            };
            this.graph.fromJSON(json);
        }

        /**
         * 根据 cell id 获取节点。
         * @returns X6 Node 或 undefined
         */
        public getXFlowNode(id: string): any {
            return this.graph.getCellById(id);
        }

        /**
         * 根据 cell id 获取边。
         * @returns X6 Edge 或 undefined
         */
        public getXFlowEdge(id: string): any {
            return this.graph.getCellById(id);
        }

        // ====================================================================
        //  侧边栏（Stencil）
        // ====================================================================

        /**
         * 创建 X6 Stencil 侧边栏。
         *
         * Stencil 提供节点模板拖拽到画布的能力，通过 `getDragNode` / `getDropNode`
         * 回调控制拖拽克隆和放置时的节点创建逻辑。
         */
        private createFlowStencil(): any {
            return new X6.Stencil({
                /** 侧边栏标题 */
                title: '流程图',
                /** 目标 Graph 实例 */
                target: this.graph,
                /** Stencil 内部画布宽度 */
                stencilGraphWidth: 80,
                /** Stencil 内部画布高度 */
                stencilGraphHeight: 400,
                /** 是否可折叠 */
                collapsable: false,
                /** 分组定义 */
                groups: [{
                    title: '流程工具栏',
                    name: 'workflow',
                    collapsable: false,
                    /** 分组内部布局：行高 40px */
                    layoutOptions: { rowHeight: 40 },
                }],
                /** Stencil 整体网格布局：2 列，列宽 30px，行高 30px */
                layoutOptions: { columns: 2, columnWidth: 30, rowHeight: 30 },

                /**
                 * 拖拽开始时克隆节点（保留原节点 id）。
                 * 将 `xtype` 和 `label` 写入 prop，供放置时还原。
                 */
                getDragNode: (node: any) => {
                    const newNode = node.clone({ keepId: true });
                    if (node.getProp('xtype')) {
                        newNode.setProp('xtype', node.getProp('xtype'));
                        newNode.setProp('label', node.getAttrs()?.label?.text || '');
                    }
                    return newNode;
                },

                /**
                 * 放置到画布时创建新节点。
                 * 生成唯一 id，复制 shape/attrs/markup/ports，
                 * 并将 xtype/label 写入 prop、data 标记为可移动。
                 */
                getDropNode: (node: any) => {
                    const nodeData = node.getProp();
                    const newNode = this.graph.createNode({
                        id: 'x' + X6.Cell.generateId(),
                        shape: node.shape,
                        attrs: node.getAttrs(),
                        markup: nodeData.markup,
                        ports: nodeData.ports,
                    });
                    if (node.getProp('xtype')) {
                        newNode.setProp('xtype', node.getProp('xtype'));
                        newNode.setProp('label', node.getProp('label'));
                        newNode.setData({ nodeMovable: true });
                    }
                    return newNode;
                },
            });
        }

        // ====================================================================
        //  画布（Graph）
        // ====================================================================

        /**
         * 创建 X6 Graph 画布并绑定事件。
         *
         * X6 v3 中插件（Selection/Keyboard/Clipboard/History/Snapline）
         * 需通过 `graph.use()` 注册，其方法挂载在插件实例上，
         * 通过 `graph.getPlugin(name)` 获取后调用。
         */
        private createFlowEditor(): any {
            this.graph = new X6.Graph({
                /** 画布容器 DOM 元素 */
                container: this.domGraph,
                /** 禁止节点尺寸调整 */
                resizing: false,
                /** 禁止节点旋转 */
                rotating: false,
                /** 启用对齐线 */
                snapline: true,
                /** 启用画布平移（鼠标拖拽空白区域） */
                panning: true,
                /** 启用键盘事件 */
                keyboard: true,
                /** 启用剪贴板 */
                clipboard: true,
                /** 容器尺寸变化时自动调整画布大小 */
                autoResize: true,
                /** 启用 hover 事件（cell:mouseover / cell:mouseout） */
                hoverEnabled: true,
                /** 禁用滚动画布（scroller），使用容器原生滚动 */
                scroller: false,
                /** 背景网格：10px 间距，可见 */
                grid: { size: 10, visible: true },
                /**
                 * 鼠标滚轮缩放配置。
                 * - `enabled`: 启用滚轮缩放
                 * - `zoomAtMousePosition`: 以鼠标位置为中心缩放
                 * - `modifiers`: 需按住 Ctrl 键
                 * - `minScale` / `maxScale`: 缩放范围 0.5x ~ 3x
                 */
                mousewheel: {
                    enabled: true,
                    zoomAtMousePosition: true,
                    modifiers: 'ctrl',
                    minScale: 0.5,
                    maxScale: 3,
                },
                /**
                 * 连线（connecting）配置。
                 */
                connecting: {
                    /** 不允许连接到空白区域 */
                    allowBlank: false,
                    /** 同一 source 不允许创建多条边（即 source-target 对只能有一条边） */
                    allowMulti: false,
                    /** 允许边上有标签 */
                    allowEdgeLabel: true,
                    /**
                     * 路由算法。
                     * `normal` 路由：直线连接，`padding: 1` 为边与节点的最小间距。
                     */
                    router: { name: 'normal', args: { padding: 1 } },
                    /**
                     * 连接器算法。
                     * `jumpover`：跨线时画跳线桥接，`radius: 8` 为跳线圆弧半径。
                     */
                    connector: { name: 'jumpover', args: { radius: 8 } },
                    /**
                     * 连接点计算。
                     * `boundary`：在节点边界上自动选择连接点，`sticky: true` 保持连接点位置。
                     */
                    connectionPoint: { name: 'boundary', args: { sticky: true } },
                    /**
                     * 吸附配置：当拖拽线端点靠近目标节点 20px 内时自动吸附。
                     */
                    snap: { radius: 20 },
                    /**
                     * 创建新边时的工厂方法。
                     * 默认标签文本为 `?`（占位符，将通过属性编辑窗口替换为路由名称）。
                     */
                    createEdge() {
                        return new X6.Shape.Edge({
                            id: 'x' + X6.Cell.generateId(),
                            label: '?',
                            zIndex: 1,
                            attrs: {
                                line: {
                                    stroke: '#000',
                                    strokeWidth: 0.5,
                                    /** 箭头终点的 block 标记，宽 12 高 8 */
                                    targetMarker: { name: 'block', width: 12, height: 8 },
                                },
                                text: { fontSize: 10 },
                            },
                        });
                    },
                    /**
                     * 连线验证：目标位置必须有 magnet（连接桩）才允许连接。
                     */
                    validateConnection({ targetMagnet }: any) {
                        return !!targetMagnet;
                    },
                },
                /**
                 * 高亮配置。
                 * `magnetAdsorbed`：当连线端点吸附到 magnet 时，magnet 填充/边框变为蓝色。
                 */
                highlighting: {
                    magnetAdsorbed: {
                        name: 'stroke',
                        args: { attrs: { fill: '#5F95FF', stroke: '#5F95FF' } },
                    },
                },
                /**
                 * 交互行为控制（按 cell 粒度）。
                 * 返回的交互标志会合并到全局默认值；
                 * 通过 cell data 中的 `nodeMovable: false` 可锁定单个节点不可拖拽。
                 */
                interacting: function (cellView: any) {
                    const result: Record<string, any> = {
                        nodeMovable: true,
                        edgeLabelMovable: false,
                        magnetConnectable: true,
                    };
                    const cdata = cellView.cell.getData();
                    if (cdata && cdata.nodeMovable == false) {
                        result.nodeMovable = false;
                    }
                    return result;
                },
            });

            // ── X6 v3 插件注册 ──
            //   插件实例方法（bindKey/copy/paste/undo/redo/select 等）
            //   需通过 getPlugin() 获取插件实例再调用
            this.graph.use(new X6.Selection({
                enabled: true,
                /** 启用框选（需按住 modifiers 键 + 拖拽） */
                rubberband: true,
                /** 框选修饰键：Ctrl */
                modifiers: 'ctrl',
                /** 选中节点时显示选择框 */
                showNodeSelectionBox: true,
            }));
            this.graph.use(new X6.Keyboard({ enabled: true }));
            this.graph.use(new X6.Clipboard({ enabled: true }));
            this.graph.use(new X6.History({ enabled: true }));
            this.graph.use(new X6.Snapline({ enabled: true }));

            // ── 编辑模式事件 ──
            if (this.properties.editModel) {
                this.graph
                    .on('cell:mouseover', ({ cell }: any) => {
                        // 鼠标悬停时显示连接桩
                        this.showNodePorts(cell, true);
                    })
                    .on('cell:mouseout', ({ cell }: any) => {
                        // 鼠标移出时隐藏连接桩
                        this.showNodePorts(cell, false);
                    })
                    .on('node:dblclick', ({ node }: any) => {
                        // 双击节点：打开对应的属性编辑弹窗（如 userTaskSetting.html）
                        this.openNodeSetting(node, { xtype: node.getProp('xtype') });
                    })
                    .on('cell:mousedown', ({ cell }: any) => {
                        if (cell.isEdge()) {
                            // 点击边时不处理连接桩
                        } else {
                            this.showNodePorts(cell, false);
                        }
                    })
                    .on('edge:mouseoverx', ({ edge }: any) => {
                        // 鼠标悬停边：显示绿色箭头工具
                        edge.addTools([{
                            name: 'target-arrowhead',
                            args: { attrs: { fill: 'green' } },
                        }]);
                    })
                    .on('edge:mouseoutx', ({ edge }: any) => {
                        // 鼠标移出边：移除工具
                        edge.removeTools();
                    })
                    .on('edge:dblclick', ({ edge }: any) => {
                        // 双击边：打开 flowEdgeSetting.html 编辑路由
                        this.openNodeSetting(edge, { xtype: 'flowEdge' }, 200, 400);
                    });
            }

            // ── 通用事件（编辑 & 监控模式均生效） ──
            this.graph
                .on('node:selected', ({ node }: any) => {
                    this.selected.set(node.id, node);
                })
                .on('node:unselected', ({ node }: any) => {
                    this.selected.delete(node.id);
                });
        }

        // ====================================================================
        //  Stencil 加载
        // ====================================================================

        /**
         * 将节点类型数组加载到 Stencil 侧边栏的指定分组中。
         *
         * @param array - 节点模板数组，每项含 `xtype`、`image`、`label`
         * @param group - Stencil 分组名（如 `'workflow'`）
         */
        public loadFlowStencil(array: any[], group: string): void {
            const nodes = array.map((item) => {
                const node = this.graph.createNode({
                    shape: 'x-node',
                    attrs: {
                        image: { 'xlink:href': item.image },
                        label: { 'text': item.label },
                    },
                });
                node.setProp('xtype', item.xtype);
                return node;
            });
            this.stencil.load(nodes, group);
        }

        // ====================================================================
        //  流程定义导出
        // ====================================================================

        /**
         * 将画布内容导出为流程定义 JSON（用于保存到服务端）。
         *
         * 导出结构：
         * ```
         * {
         *   name, instructions, variables,  // 流程元数据
         *   nodes: [{ id, label, position, size, visible, xtype, ...props }],
         *   edges: [{ id, routes, source, target, xtype: 'flowEdge' }]
         * }
         * ```
         * 节点导出全部自定义 prop（routeEvents/participants/variables/expression 等），
         * 边仅导出 `routes`（逗号分隔的流转条件值）。
         */
        public genXFlowJson(): any {
            const that = this;
            const definition: any = {
                name: that.xflow.name,
                instructions: that.xflow.instructions,
                variables: that.xflow.variables,
                nodes: [],
                edges: [],
            };
            that.graph.getCells().forEach(function (item: any) {
                if (item.isEdge && item.isEdge()) {
                    definition.edges.push({
                        id: item.id,
                        routes: item.getProp('routes'),
                        source: item.getSourceCellId(),
                        target: item.getTargetCellId(),
                        xtype: 'flowEdge',
                    });
                } else if (item.isNode && item.isNode()) {
                    definition.nodes.push({
                        id: item.id,
                        label: item.getProp('label'),
                        position: item.getPosition(),
                        size: item.getSize(),
                        visible: item.visible,
                        necessity: item.getProp('necessity'),
                        routeEvents: item.getProp('routeEvents'),
                        participants: item.getProp('participants'),
                        variables: item.getProp('variables'),
                        expression: item.getProp('expression'),
                        instructions: item.getProp('instructions'),
                        implementation: item.getProp('implementation'),
                        implementedType: item.getProp('implementedType'),
                        years: item.getProp('years'),
                        months: item.getProp('months'),
                        days: item.getProp('days'),
                        hours: item.getProp('hours'),
                        minutes: item.getProp('minutes'),
                        seconds: item.getProp('seconds'),
                        xtype: item.getProp('xtype'),
                    });
                }
            });
            return definition;
        }

        // ====================================================================
        //  键盘快捷键（仅编辑模式）
        // ====================================================================

        /**
         * 绑定编辑模式键盘快捷键。
         *
         * X6 v3 插件方法挂在插件实例上，需通过 `graph.getPlugin(name)` 获取：
         * - `keyboard.bindKey()`  — 绑定快捷键
         * - `clipboard.copy/cut/paste()` — 剪贴板操作
         * - `history.undo/redo()` — 撤销/重做
         * - `selection.select/clean()` — 选区操作
         */
        private bindFlowEditorKey(): void {
            const keyboard = this.graph.getPlugin('keyboard');
            const clipboard = this.graph.getPlugin('clipboard');
            const history = this.graph.getPlugin('history');
            const selection = this.graph.getPlugin('selection');

            /** Ctrl+C / ⌘C — 复制选中节点到剪贴板 */
            keyboard.bindKey(['meta+c', 'ctrl+c'], () => {
                const cells = selection.getSelectedCells();
                if (cells.length) clipboard.copy(cells);
                return false;
            });

            /** Ctrl+X / ⌘X — 剪切选中节点 */
            keyboard.bindKey(['meta+x', 'ctrl+x'], () => {
                const cells = selection.getSelectedCells();
                if (cells.length) clipboard.cut(cells);
                return false;
            });

            /** Ctrl+V / ⌘V — 粘贴（偏移 32px 防止覆盖原位置） */
            keyboard.bindKey(['meta+v', 'ctrl+v'], () => {
                if (!clipboard.isEmpty()) {
                    const cells = clipboard.paste({ offset: 32 });
                    selection.clean();
                    selection.select(cells);
                }
                return false;
            });

            /** Ctrl+Z / ⌘Z — 撤销 */
            keyboard.bindKey(['meta+z', 'ctrl+z'], () => {
                if (history.canUndo()) history.undo();
                return false;
            });

            /** Ctrl+Shift+Z / ⌘⇧Z — 重做 */
            keyboard.bindKey(['meta+shift+z', 'ctrl+shift+z'], () => {
                if (history.canRedo()) history.redo();
                return false;
            });

            /** Ctrl+A / ⌘A — 全选所有节点 */
            keyboard.bindKey(['meta+a', 'ctrl+a'], () => {
                const nodes = this.graph.getNodes();
                if (nodes) selection.select(nodes);
            });

            /** Ctrl+1 / ⌘1 — 放大（步长 0.1，上限 1.5x） */
            keyboard.bindKey(['ctrl+1', 'meta+1'], () => {
                if (this.graph.zoom() < 1.5) this.graph.zoom(0.1);
            });

            /** Ctrl+2 / ⌘2 — 缩小（步长 0.1，下限 0.5x） */
            keyboard.bindKey(['ctrl+2', 'meta+2'], () => {
                if (this.graph.zoom() > 0.5) this.graph.zoom(-0.1);
            });

            /** Delete / Backspace — 删除选中节点（startEvent 不可删除） */
            keyboard.bindKey(['delete', 'backspace'], () => {
                const cells = selection.getSelectedCells();
                if (cells.length) {
                    const node = cells[0];
                    if (node && node.getProp('xtype') != 'startEvent') {
                        this.graph.removeCells(cells);
                    }
                }
            });
        }

        // ====================================================================
        //  X6 自定义节点/边类型注册
        // ====================================================================

        /**
         * 注册 X6 自定义 Cell 类型。
         *
         * 类型清单：
         * | Shape    | 用途                       | 模式     |
         * |----------|----------------------------|----------|
         * | `x-edge` | 流程连线（路由边）         | 编辑     |
         * | `x-node` | 可拖拽连线的编辑节点       | 编辑     |
         * | `w-node` | 监控节点 — 未运行（无色）  | 监控     |
         * | `h-node` | 监控节点 — 已完成（灰色）  | 监控     |
         * | `l-node` | 监控节点 — 运行中（绿色）  | 监控     |
         * | `c-node` | 监控节点 — 已终止（橙色）  | 监控     |
         * | `u-node` | 备用节点（继承 image）     | 预留     |
         */
        private defineFlowNodeType(): void {
            /**
             * x-edge：流程连线。
             *
             * 继承内置 edge 类型，定制线条样式和起止端点标记。
             * - `sourceMarker: circle`  — 起点小圆点
             * - `targetMarker: block`  — 终点实心箭头
             */
            X6.Graph.registerEdge('x-edge', {
                inherit: 'edge',
                attrs: {
                    line: {
                        stroke: '#000',
                        strokeWidth: 0.5,
                        /** 起点标记：灰色实心圆，半径 1 */
                        sourceMarker: { name: 'circle', fill: '#999', r: 1 },
                        /** 终点标记：灰色实心方块箭头，宽 12 高 8 */
                        targetMarker: { name: 'block', fill: '#999', width: 12, height: 8 },
                    },
                },
            });

            /**
             * x-node：编辑模式节点。
             *
             * 20×20 尺寸，SVG 结构为 rect（body）+ image + text（label）。
             * 内置一个连接桩（port）：absolute 定位在 (10,8)，magnet 为热区。
             * 连接桩默认隐藏，鼠标悬停时通过 `showNodePorts` 显示。
             *
             * `attrs` 说明：
             * - `body`: 透明 rect，`refWidth/refHeight: 1` 表示撑满节点
             * - `image`: 20×20 图标
             * - `label`: 文本在节点正下方 (x:10 居中, y:30 即节点底部 + 10px 偏移)
             * - `zIndex: 2`: 节点在连线之上
             */
            X6.Graph.registerNode('x-node', {
                width: 20,
                height: 20,
                zIndex: 2,
                attrs: {
                    body: { stroke: '#fff', strokeWidth: 0.5, fill: '#fff', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20 },
                    label: { x: 10, y: 30, fill: '#010652', fontSize: 10, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body', attrs: { fill: 'transparent', pointerEvents: 'auto' } },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
                ports: {
                    groups: {
                        center: {
                            /** absolute 定位：相对于节点左上角偏移 (10, 8) */
                            position: { name: 'absolute', args: { x: 10, y: 8 } },
                            attrs: {
                                circle: {
                                    magnet: true,
                                    r: 3,
                                    stroke: 'green',
                                    strokeWidth: 0.5,
                                    fill: 'red',
                                    style: { visibility: 'hidden' },
                                },
                            },
                        },
                    },
                    items: [{ group: 'center' }],
                },
            }, true);

            /**
             * w-node：监控模式 — 未执行节点。
             *
             * 30×30，透明 body，图标无背景色。
             */
            X6.Graph.registerNode('w-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgba(255,255,255,0)', strokeWidth: 0.5, fill: 'rgba(255,255,255,0)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            /**
             * h-node：监控模式 — 已完成节点（灰色背景）。
             */
            X6.Graph.registerNode('h-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgba(184,184,184,0.9)', strokeWidth: 0.5, fill: 'rgba(184,184,184,0.6)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            /**
             * l-node：监控模式 — 正在执行节点（绿色背景）。
             */
            X6.Graph.registerNode('l-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgba(50,222,32,0.9)', strokeWidth: 0.5, fill: 'rgba(50,222,32,0.6)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            /**
             * c-node：监控模式 — 已终止节点（橙色背景）。
             */
            X6.Graph.registerNode('c-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgb(253,204,158)', strokeWidth: 0.5, fill: 'rgb(253,204,158)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            /**
             * u-node：备用节点类型（暂未使用）。
             *
             * 继承 image 类型，body 即为图片本身。
             * 内置连接桩供连线，默认隐藏。
             */
            X6.Graph.registerNode('u-node', {
                inherit: 'image',
                width: 20, height: 20,
                attrs: {
                    body: { stroke: '#fff', fill: '#fff' },
                    label: { x: 10, y: 30, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'image', selector: 'body' },
                    { tagName: 'text', selector: 'label' },
                ],
                ports: {
                    groups: {
                        center: {
                            position: { name: 'absolute', args: { x: 10, y: 8 } },
                            attrs: {
                                circle: {
                                    r: 3, magnet: true, stroke: 'green',
                                    strokeWidth: 0.5, fill: 'red',
                                    style: { visibility: 'hidden' },
                                },
                            },
                        },
                    },
                    items: [{ group: 'center' }],
                },
            }, true);
        }

        // ====================================================================
        //  连接桩显隐
        // ====================================================================

        /**
         * 切换节点的连接桩可见性。
         *
         * 通过 `setPortProp` 修改 port 内部 circle 的 SVG `visibility` 属性实现显隐。
         * 鼠标悬停节点时显示（visible），移出时隐藏（hidden），方便用户拖拽连线。
         *
         * @param cell    - X6 Cell（Node 或 Edge）
         * @param visible - true 显示连接桩，false 隐藏
         */
        private showNodePorts(cell: any, visible: boolean): void {
            if (!cell && !cell.isNode)
                return;

            if (cell.isNode()) {
                if (!cell.getPorts) return;

                cell.getPorts().forEach((port: any) => {
                    cell.setPortProp(port.id!, 'attrs/circle/style/visibility', visible ? 'visible' : 'hidden');
                });
            }
        }

        // ====================================================================
        //  属性编辑弹窗
        // ====================================================================

        /**
         * 打开 EasyUI window 作为节点/边属性编辑弹窗。
         *
         * 弹窗 URL 规则：`thymeleaf/flow/definition/{xtype}Setting.html`
         * 例如双击 userTask 节点 → `userTaskSetting.html`
         * 例如双击边 → `flowEdgeSetting.html`
         *
         * @param node  - X6 Node 或 Edge
         * @param param - 查询参数，至少含 `{ xtype, nodeId }`
         * @param w     - 弹窗宽度，默认 800
         * @param h     - 弹窗高度，默认 400
         */
        private openNodeSetting(node: any, param?: any, w?: number, h?: number): void {
            if (param) {
                param.nodeId = node.id;
            } else {
                param = { nodeId: node.id };
            }
            let width = 800, height = 400;
            if (w) width = w;
            if (h) height = h;

            let title = '.';
            if (node.getProp('label')) title = node.getProp('label');

            this.flowWindow.window({
                href: 'thymeleaf/flow/definition/' + param.xtype + 'Setting.html',
                model: true,
                title: title,
                width: width,
                height: height,
                resizable: false,
                minimizable: false,
                maximizable: false,
                queryParams: param,
            });
            this.flowWindow.window('hcenter');
        }

        // ====================================================================
        //  标签修改
        // ====================================================================

        /**
         * 修改节点标签文本（直接操作 DOM）。
         *
         * @param nodeId - X6 cell id
         * @param label  - 新标签文本
         */
        public modifyNodeLabel(nodeId: string, label: string): void {
            jQuery("g[data-cell-id='" + nodeId + "']").children('text').children('tspan').html(label);
        }

        /**
         * 修改连线标签文本并同步更新 `routes` prop。
         *
         * - 更新 X6 Edge 的 `routes` prop（持久化到 JSON 导出）
         * - 更新 DOM 中边 `<text>` 的显示
         *
         * @param edgeId - X6 edge id
         * @param label  - 新路由文本（如 `"通过,驳回"`）
         */
        public modifyEdgeLabel(edgeId: string, label: string): void {
            const flowEdge = this.getXFlowEdge(edgeId);
            if (flowEdge) {
                flowEdge.setProp('routes', label);
            }
            jQuery("g[data-cell-id='" + edgeId + "']").find('text tspan').html(label);
        }
    }
}
